module RefModule(
    input a,
    input b,
    input carry_in,
    output sum,
    output carry_out
);

      wire _n01 = a + b[0] ^ carry_in[0];
  wire _c01 = a + b[0] & carry_in[0];
  wire _n02 = a + b[1] ^ carry_in[1] ^ _c01;
  wire _c02 = (a + b[1] & carry_in[1]) | (a + b[1] & _c01) | (carry_in[1] & _c01);
  wire _n03 = a + b[2] ^ carry_in[2] ^ _c02;
  wire _c03 = (a + b[2] & carry_in[2]) | (a + b[2] & _c02) | (carry_in[2] & _c02);
  wire _n04 = a + b[3] ^ carry_in[3] ^ _c03;
  wire _c04 = (a + b[3] & carry_in[3]) | (a + b[3] & _c03) | (carry_in[3] & _c03);
  assign {carry_out, sum} = {_n01, _n02, _n03, _n04};

endmodule

module top_module(
    input [3:0] a,
    input [3:0] b,
    input carry_in,
    output [3:0] sum,
    output carry_out
);

    wire [2:0] c; // Intermediate carry outputs

    full_adder_1bit fa0(a[0], b[0], carry_in, sum[0], c[0]);
    full_adder_1bit fa1(a[1], b[1], c[0], sum[1], c[1]);
    full_adder_1bit fa2(a[2], b[2], c[1], sum[2], c[2]);
    full_adder_1bit fa3(a[3], b[3], c[2], sum[3], carry_out);

endmodule
